using System.ComponentModel.DataAnnotations;

namespace sv_9f6ad74a4bbd4697a5ca16a5bbbd4c6c.Models;

public class AppointmentFormModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = "";

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = "";

    // Step 2
    [Required(ErrorMessage = "Preferred doctor is required.")]
    public string Doctor { get; set; } = "";

    [Required(ErrorMessage = "Date is required.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time slot is required.")]
    public string TimeSlot { get; set; } = "";

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string ReasonForVisit { get; set; } = "";
}

public class PatientValidationResult
{
    public bool IsValid => Errors.Count == 0;
    public Dictionary<string, string> Errors { get; set; } = new();
}

using sv_9f6ad74a4bbd4697a5ca16a5bbbd4c6c.Models;

namespace sv_9f6ad74a4bbd4697a5ca16a5bbbd4c6c.Services;

public interface IAppointmentService
{
    Task<List<string>> GetDoctorsAsync();
    Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date);
    Task<PatientValidationResult> ValidatePatientAsync(AppointmentFormModel model);
}

public class AppointmentService : IAppointmentService
{
    private static readonly List<string> Doctors = ["Dr. Smith", "Dr. Johnson", "Dr. Williams", "Dr. Brown"];

    private static readonly List<string> AllSlots =
        ["9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM", "11:00 AM", "1:00 PM", "1:30 PM", "2:00 PM", "3:00 PM"];

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return all slots for any valid doctor+date
        return Task.FromResult(new List<string>(AllSlots));
    }

    public Task<PatientValidationResult> ValidatePatientAsync(AppointmentFormModel model)
    {
        var result = new PatientValidationResult();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(model.Email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors[nameof(model.Email)] = "Account has outstanding balance";
        }

        // Reject "None" insurance with "Dr. Smith"
        if (string.Equals(model.InsuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(model.Doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            result.Errors[nameof(model.Doctor)] = "Selected doctor does not accept self-pay patients";
        }

        // Reject "10:00 AM" as taken (race condition simulation)
        if (string.Equals(model.TimeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            result.Errors[nameof(model.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

