arguments.file_text:
@page "/book-appointment"
@rendermode InteractiveServer
@using sv_9f6ad74a4bbd4697a5ca16a5bbbd4c6c.Models
@using sv_9f6ad74a4bbd4697a5ca16a5bbbd4c6c.Services
@inject IAppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book an Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmitAsync" FormName="appointment">
    <DataAnnotationsValidator />

    @* ── STEP 1 ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.TryGetValue(nameof(Model.Email), out var emailErr))
            {
                <div class="validation-message">@emailErr</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2Async">
                Next
            </button>
        }
    </fieldset>

    @* ── STEP 2 ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor"
                             @bind-Value:after="OnDoctorOrDateChangedAsync">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (serverErrors.TryGetValue(nameof(Model.Doctor), out var docErr))
                {
                    <div class="validation-message">@docErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate"
                           @bind-Value:after="OnDoctorOrDateChangedAsync" />
                <ValidationMessage For="() => Model.AppointmentDate" />
                @if (Model.AppointmentDate.HasValue && Model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
                {
                    <div class="validation-message">Date must be in the future.</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeslot">Time Slot</label>
                <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.TryGetValue(nameof(Model.TimeSlot), out var slotErr))
                {
                    <div class="validation-message">@slotErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="Model.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">
                Back
            </button>
            <button type="button" class="btn btn-primary me-2" @onclick="CheckAvailabilityAsync">
                Check Availability
            </button>
            @if (availabilityConfirmed)
            {
                <button type="submit" class="btn btn-success">
                    Confirm Appointment
                </button>
            }
        </fieldset>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentFormModel Model { get; set; } = new();

    private bool showStep2;
    private bool availabilityConfirmed;
    private bool submitted;

    private List<string> doctors = [];
    private List<string> timeSlots = [];
    private Dictionary<string, string> serverErrors = new();

    private EditContext? editContext;

    protected override void OnInitialized()
    {
        editContext = new EditContext(Model);
    }

    private async Task ProceedToStep2Async()
    {
        // Validate only step-1 fields
        editContext = new EditContext(Model);
        var isValid = !string.IsNullOrWhiteSpace(Model.PatientName)
                      && !string.IsNullOrWhiteSpace(Model.Email)
                      && new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email)
                      && !string.IsNullOrWhiteSpace(Model.Phone)
                      && !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

        if (!isValid)
        {
            // Trigger validation messages by validating the full model;
            // step-2 fields won't show because the fieldset is hidden.
            editContext.Validate();
            return;
        }

        doctors = await AppointmentService.GetDoctorsAsync();
        showStep2 = true;
    }

    private async Task OnDoctorOrDateChangedAsync()
    {
        serverErrors.Remove(nameof(Model.Doctor));
        serverErrors.Remove(nameof(Model.TimeSlot));
        availabilityConfirmed = false;

        if (!string.IsNullOrWhiteSpace(Model.Doctor) && Model.AppointmentDate.HasValue
            && Model.AppointmentDate.Value > DateOnly.FromDateTime(DateTime.Today))
        {
            Model.TimeSlot = "";
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
    }

    private async Task CheckAvailabilityAsync()
    {
        serverErrors.Clear();
        availabilityConfirmed = false;

        // Client-side guard on date
        if (Model.AppointmentDate.HasValue && Model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            return;
        }

        // Validate step-2 required fields locally first
        editContext = new EditContext(Model);
        if (!editContext.Validate())
        {
            return;
        }

        var result = await AppointmentService.ValidatePatientAsync(Model);

        if (!result.IsValid)
        {
            serverErrors = new Dictionary<string, string>(result.Errors);
            return;
        }

        availabilityConfirmed = true;
    }

