+            return;
+        }
+
+        // Validate step-2 required fields locally first
+        editContext = new EditContext(Model);
+        if (!editContext.Validate())
+        {
+            return;
+        }
+
+        var result = await AppointmentService.ValidatePatientAsync(Model);
+
+        if (!result.IsValid)
+        {
+            serverErrors = new Dictionary<string, string>(result.Errors);
+            return;
+        }
+
+        availabilityConfirmed = true;
+    }
+
+    private void BackToStep1()
+    {
+        showStep2 = false;
+        availabilityConfirmed = false;
+        serverErrors.Clear();
+    }
+
+    private async Task HandleSubmitAsync()
+    {
+        // Re-run server validation before final submit
+        var result = await AppointmentService.ValidatePatientAsync(Model);
+        if (!result.IsValid)
+        {
+            serverErrors = new Dictionary<string, string>(result.Errors);
+            availabilityConfirmed = false;
+            return;
+        }
+
+        submitted = true;
